#!/usr/bin/env tsx
//
// External-corpus seed merge with Jaccard dedup (mirrors the M5
// scripts/eval/find_similar/merge-seeds.ts pattern).
//
// Combines the hand-baseline + 3 lens-flavored seed files in an external
// corpus dir into one merged set. Same dedup logic as M5: pairwise Jaccard
// of query-tokens >= 0.7 is a duplicate; keep the earlier (hand-vintage)
// entry, drop the later.
//
// Run:
//   npx tsx scripts/eval/find_similar/external/merge-seeds.ts \
//     --corpus-dir atelier/eval/find_similar/external-corpora/claude-agent-sdk

import { readFileSync, writeFileSync, existsSync } from 'node:fs';
import { join, resolve } from 'node:path';

import { parse as parseYaml, stringify as yamlStringify } from 'yaml';

interface Seed {
  id: string;
  description?: string;
  query: string;
  trace_id?: string;
  expected: string[];
}

const JACCARD_DUP_THRESHOLD = 0.7;
const MIN_TOKEN_LEN = 3;

function tokenize(query: string): Set<string> {
  return new Set(
    query
      .toLowerCase()
      .split(/[^a-z0-9_]+/)
      .map((t) => t.replace(/[^a-z0-9]/g, ''))
      .filter((t) => t.length >= MIN_TOKEN_LEN),
  );
}

function jaccard(a: Set<string>, b: Set<string>): number {
  if (a.size === 0 && b.size === 0) return 1;
  let intersection = 0;
  for (const t of a) if (b.has(t)) intersection += 1;
  const union = a.size + b.size - intersection;
  return union === 0 ? 0 : intersection / union;
}

interface RecordedSeed extends Seed {
  source: string;
  tokens: Set<string>;
}

function parseArg(name: string, fallback: string | undefined): string {
  const flag = `--${name}`;
  const idx = process.argv.indexOf(flag);
  if (idx === -1) {
    if (fallback !== undefined) return fallback;
    throw new Error(`required flag --${name} missing`);
  }
  const value = process.argv[idx + 1];
  if (!value) throw new Error(`--${name} requires a value`);
  return value;
}

function main(): void {
  const corpusDir = resolve(parseArg('corpus-dir', undefined));
  const sources = [
    { path: join(corpusDir, 'seeds-hand.yaml'), label: 'hand-baseline' },
    { path: join(corpusDir, 'seeds-analyst.yaml'), label: 'analyst-lens' },
    { path: join(corpusDir, 'seeds-dev.yaml'), label: 'dev-lens' },
    { path: join(corpusDir, 'seeds-pm.yaml'), label: 'pm-lens' },
  ];

  const all: RecordedSeed[] = [];
  for (const src of sources) {
    if (!existsSync(src.path)) {
      console.warn(`[merge] ${src.path} not found; skipping`);
      continue;
    }
    const body = readFileSync(src.path, 'utf8');
    const parsed = parseYaml(body) as { seeds?: Seed[] };
    const seeds = parsed.seeds ?? [];
    for (const s of seeds) {
      all.push({ ...s, source: src.label, tokens: tokenize(s.query) });
    }
    console.log(`[merge] ${src.label}: ${seeds.length} seeds`);
  }

  // Dedup by Jaccard. Keep the earlier (lower-index) entry.
  const kept: RecordedSeed[] = [];
  let dropped = 0;
  for (const candidate of all) {
    const dupOf = kept.find(
      (k) =>
        k.query.trim() === candidate.query.trim() ||
        jaccard(k.tokens, candidate.tokens) >= JACCARD_DUP_THRESHOLD,
    );
    if (dupOf) {
      dropped += 1;
      console.log(
        `[merge] DROP  ${candidate.id} (${candidate.source}) ~ ${dupOf.id} (${dupOf.source})`,
      );
      continue;
    }
    kept.push(candidate);
  }

  console.log(`\n[merge] kept ${kept.length}; dropped ${dropped} (Jaccard >= ${JACCARD_DUP_THRESHOLD})`);

  const out = {
    seeds: kept.map((s) => {
      const o: Seed = { id: s.id, query: s.query, expected: s.expected };
      if (s.description !== undefined) o.description = s.description;
      if (s.trace_id !== undefined) o.trace_id = s.trace_id;
      return o;
    }),
  };

  const header = [
    `# Merged seed set (${corpusDir}; §26 wider eval).`,
    `# hand + analyst + dev + pm lens sources -> deduped by query-token`,
    `# Jaccard >= ${JACCARD_DUP_THRESHOLD}. Generated by scripts/eval/find_similar/external/`,
    `# merge-seeds.ts; do not hand-edit.`,
    '',
  ].join('\n');

  const outPath = join(corpusDir, 'seeds-merged.yaml');
  writeFileSync(outPath, header + yamlStringify(out));
  console.log(`[merge] wrote ${outPath}`);
}

main();
